using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Shared state for the note-taking tool ---
var notebook = new List<string>();

// --- Tool definitions ---
AITool searchTool = AIFunctionFactory.Create(SearchWeb,
    new AIFunctionFactoryOptions { Name = "search_web" });

AITool noteTool = AIFunctionFactory.Create(TakeNote,
    new AIFunctionFactoryOptions { Name = "take_note" });

AITool readNotesTool = AIFunctionFactory.Create(ReadNotes,
    new AIFunctionFactoryOptions { Name = "read_notes" });

// --- Build the chat client via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic, you:
        1. Search the web multiple times with different queries to gather diverse information.
        2. Take notes on the key findings from each search using the take_note tool.
        3. After gathering enough information (at least 3 searches), read your notes and
           produce a well-structured summary with sections and key takeaways.
        Always cite which search results informed each part of your summary.
        """,
    name: "ResearchAgent",
    description: "Researches a topic by searching the web and summarizing findings.",
    tools: [searchTool, noteTool, readNotesTool]);

// --- Get the research topic ---
string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "artificial intelligence";
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent ---
var messages = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

var session = await agent.CreateSessionAsync("research");

await foreach (var update in agent.RunStreamingAsync(messages, session, cancellationToken: CancellationToken.None))
{
    foreach (var content in update.Contents)
    {
        if (content is TextContent text)
        {
            Console.Write(text.Text);
        }
    }
}

Console.WriteLine("\n\n📒 Notes taken during research:");
for (int i = 0; i < notebook.Count; i++)
{
    Console.WriteLine($"  {i + 1}. {notebook[i]}");
}

// --- Tool implementations ---

[Description("Search the web for information on a query. Returns a list of search result snippets.")]
static string SearchWeb(
    [Description("The search query to look up")] string query)
{
    // Simulated web search results for demonstration.
    // In production, integrate a real search API (e.g., Bing Search).
    var results = new StringBuilder();
    results.AppendLine($"Search results for: \"{query}\"");
    results.AppendLine();

    var simulatedResults = GetSimulatedResults(query);
    for (int i = 0; i < simulatedResults.Length; i++)
    {
        results.AppendLine($"[{i + 1}] {simulatedResults[i]}");
    }

    Console.WriteLine($"  🌐 Searched: \"{query}\" ({simulatedResults.Length} results)");
    return results.ToString();
}

[Description("Save an important note or finding from your research. Use this to track key information.")]
string TakeNote(
    [Description("The note content to save")] string note)
{
    notebook.Add(note);
    Console.WriteLine($"  📝 Note saved ({notebook.Count} total)");
    return $"Note saved. You now have {notebook.Count} note(s).";
}

[Description("Read all notes taken so far during the research session.")]
string ReadNotes()
{
    if (notebook.Count == 0)
    {
        return "No notes taken yet.";
    }

    var sb = new StringBuilder();
    sb.AppendLine("Current research notes:");
    for (int i = 0; i < notebook.Count; i++)
    {
        sb.AppendLine($"  [{i + 1}] {notebook[i]}");
    }

    return sb.ToString();
}

static string[] GetSimulatedResults(string query)
{
    var q = query.ToLowerInvariant();

    if (q.Contains("quantum computing"))
    {
        return
        [
            "Quantum computing uses qubits that can exist in superposition, enabling parallel computation. IBM and Google lead with 1000+ qubit processors expected by 2026. — Nature Reviews Physics, 2025",
            "Key applications include drug discovery, cryptography, and optimization problems. Quantum advantage has been demonstrated for specific sampling tasks. — MIT Technology Review",
            "Error correction remains the biggest challenge. Surface codes and topological qubits are promising approaches to fault-tolerant quantum computing. — arxiv.org",
        ];
    }

    if (q.Contains("climate") || q.Contains("renewable"))
    {
        return
        [
            "Global renewable energy capacity reached 4,000 GW in 2025, with solar accounting for 60% of new installations. — International Energy Agency",
            "Battery storage costs have fallen 90% since 2010, making grid-scale storage economically viable. Sodium-ion batteries are emerging as alternatives to lithium. — BloombergNEF",
            "The Paris Agreement targets require tripling renewable capacity by 2030. Current trajectories suggest a 2.5°C warming scenario. — IPCC AR7",
        ];
    }

    if (q.Contains("ai") || q.Contains("artificial intelligence") || q.Contains("machine learning"))
    {
        return
        [
            "Large language models have scaled to trillions of parameters with emergent reasoning capabilities. Multimodal models now process text, images, audio, and video. — Stanford HAI Report 2025",
            "AI regulation frameworks are being implemented globally. The EU AI Act classifies systems by risk level. The US follows a sector-specific approach. — Brookings Institution",
            "AI agents capable of autonomous multi-step reasoning and tool use are transforming software development, scientific research, and business operations. — McKinsey Global Institute",
        ];
    }

    // Generic fallback
    return
    [
        $"Recent developments in {query} show significant progress in research and practical applications. Multiple institutions are actively investigating this area. — Academic Journals 2025",
        $"Industry analysts predict the {query} market will grow substantially over the next five years, driven by technological advances and increased investment. — Market Research Report",
        $"Experts highlight both opportunities and challenges in {query}, emphasizing the need for interdisciplinary collaboration and ethical considerations. — Policy Brief 2025",
    ];
}

